class Solution {
    public int subarraySum(int[] nums, int k) {
        Map<Integer, Integer> count = new HashMap<>();
        count.put(0, 1);   // empty prefix
        int sum = 0, result = 0;

        for (int num : nums) {
            sum += num;
            result += count.getOrDefault(sum - k, 0);
            count.put(sum, count.getOrDefault(sum, 0) + 1);
        }
        return result;
    }
}
